import{_ as e,o as a,c as t,a1 as r}from"./chunks/framework.D-9tmlIu.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"posts/JavaScript/复习.md","filePath":"posts/JavaScript/复习.md"}'),d={name:"posts/JavaScript/复习.md"};function s(i,o,c,n,l,p){return a(),t("div",null,[...o[0]||(o[0]=[r('<h2 id="🏗️-它具体做了什么-幕后翻译官" tabindex="-1">🏗️ 它具体做了什么？（幕后翻译官） <a class="header-anchor" href="#🏗️-它具体做了什么-幕后翻译官" aria-label="Permalink to &quot;🏗️ 它具体做了什么？（幕后翻译官）&quot;">​</a></h2><p>你的浏览器（比如 Chrome、Edge、Safari）其实是<strong>看不懂</strong> <code>.md</code>（Markdown）文件的，它只能看懂 <code>.html</code>、<code>.css</code> 和 <code>.js</code> 文件。</p><p>当你运行 <code>npm run build</code> 时，VitePress 会在后台疯狂运转，帮你做以下三件事： #v</p><h3 id="_1-markdown-变-html-大转译" tabindex="-1">1. Markdown 变 HTML（大转译） <a class="header-anchor" href="#_1-markdown-变-html-大转译" aria-label="Permalink to &quot;1. Markdown 变 HTML（大转译）&quot;">​</a></h3><p>它会把你 <code>posts/</code> 文件夹里所有的文章（比如 <code>first.md</code>），全部转换成标准的 <code>first.html</code> 网页文件。</p><h3 id="_2-注入灵魂-样式与交互" tabindex="-1">2. 注入灵魂（样式与交互） <a class="header-anchor" href="#_2-注入灵魂-样式与交互" aria-label="Permalink to &quot;2. 注入灵魂（样式与交互）&quot;">​</a></h3><p>它会把你在 <code>.vitepress/config.mts</code> 里配置的网站标题、导航栏、侧边栏，以及主题的精美样式，全部融合到每一个网页中，确保网站在手机和电脑上看起来都非常专业。</p><h3 id="_3-极致压缩-瘦身" tabindex="-1">3. 极致压缩（瘦身） <a class="header-anchor" href="#_3-极致压缩-瘦身" aria-label="Permalink to &quot;3. 极致压缩（瘦身）&quot;">​</a></h3><p>它会把所有的代码进行“脱水”压缩（去掉空格、缩进，压缩图片和脚本体积），让最终生成的网站文件变得极小，这样别人打开你网站时的<strong>加载速度就会快到飞起</strong>。</p><h2 id="📦-打包后的产物在哪里" tabindex="-1">📦 打包后的产物在哪里？ <a class="header-anchor" href="#📦-打包后的产物在哪里" aria-label="Permalink to &quot;📦 打包后的产物在哪里？&quot;">​</a></h2><p>这个命令运行完后，它会在你的 <code>.vitepress</code> 文件夹下生成一个名为 <strong><code>dist</code></strong>（Distribution 的缩写，意为分发、发布）的文件夹。</p><ul><li><p>这个 <code>dist</code> 文件夹里装的就是你网站的<strong>完整最终成品</strong>。</p></li><li><p>你可以把这个 <code>dist</code> 文件夹丢给任何一个服务器（比如阿里云、腾讯云、GitHub Pages、Cloudflare），你的网站就能立刻上线。</p></li></ul><h2 id="🤔-我需要天天在本地运行它吗" tabindex="-1">🤔 我需要天天在本地运行它吗？ <a class="header-anchor" href="#🤔-我需要天天在本地运行它吗" aria-label="Permalink to &quot;🤔 我需要天天在本地运行它吗？&quot;">​</a></h2><p><strong>不需要。</strong></p><p>因为你已经配置好了 GitHub Actions（或者 Cloudflare Pages）的自动化部署：</p><ol><li><p>你只需要在本地用 GitHub Desktop 做好 <code>Commit</code> 和 <code>Push</code>，把修改后的<strong>源码</strong>传上去。</p></li><li><p>云端的服务器在收到你的推送后，会自动在它们那边免费帮你运行一次 <code>npm run build</code>，生成 <code>dist</code> 并发布。</p></li></ol><p><strong>那你什么时候会用到它？</strong> 只有当你修改了网站的底层配置（比如大改了导航栏结构、换了主题皮肤），并且<strong>想在本地电脑上先预览一下最终打包成型的网站有没有出 bug</strong> 时，你才会在本地终端里敲下这个命令进行测试。</p>',17)])])}const m=e(d,[["render",s]]);export{u as __pageData,m as default};
